mapper.select:
SELECT p.ID, p.WORKPLACE_ID, p.USER_ID, p.FROM_DATE, p.TO_DATE, p.WAGE_TYPE, p.HOURLY_WAGE, p.MONTHLY_WAGE, p.WORKED_DAYS, p.WORKED_MINUTES, p.BASE_WAGE, p.WEEKLY_HOLIDAY_PAY, p.BONUS_AMOUNT, p.BONUS_NOTE, p.DEDUCTION_AMOUNT, p.DEDUCTION_NOTE, p.TOTAL_WAGE, p.DAILY_SNAPSHOT, p.STATUS, p.CREATED_AT, p.UPDATED_AT, u.NAME AS USER_NAME, u.PROFILE_COLOR, w.NAME AS WORKPLACE_NAME FROM PAYSLIPS p JOIN USERS u ON u.ID = p.USER_ID JOIN WORKPLACES w ON w.ID = p.WORKPLACE_ID WHERE p.USER_ID = #{userId} AND p.STATUS = 'CONFIRMED'
AND p.WORKPLACE_ID = #{workplaceId}
AND p.FROM_DATE >= #{fromDate}
AND p.TO_DATE <= #{toDate}
ORDER BY p.CREATED_AT DESC

mapper.update:
UPDATE PAYSLIPS
SET BONUS_AMOUNT = #{bonusAmount},
    BONUS_NOTE   = #{bonusNote},
    TOTAL_WAGE   = #{totalWage}
WHERE ID = #{id}

UPDATE PAYSLIPS
SET DEDUCTION_AMOUNT = #{deductionAmount},
    TOTAL_WAGE       = #{totalWage}
WHERE ID = #{id}

UPDATE PAYSLIPS
SET STATUS = #{status}
WHERE ID = #{id}
